# BAD: module-level singleton; tied to a specific provider, hard to test
from openai import OpenAI
_client = OpenAI()

def summarize(text: str) -> str:
    return _client.chat.completions.create(...).choices[0].message.content


# GOOD: take collaborators as parameters
from typing import Protocol

class LLMClient(Protocol):
    def complete(self, prompt: str) -> str: ...

def summarize(text: str, client: LLMClient) -> str:
    return client.complete(text)

import functools
import tiktoken


@functools.cache         # one-shot cache; cleared per process
def _tokenizer():
    # Loads only on first call, never on import.
    return tiktoken.get_encoding("o200k_base")


def count_tokens(text: str) -> int:
    return len(_tokenizer().encode(text))
